declare const self: DedicatedWorkerGlobalScope

// ============== 配置变量 ==============
// 是否对 sQTL 和 eQTL 的 positions 去重（针对返回的 start 字段）
const DEDUPLICATE_QTL_POSITIONS = true

// ============== CDS 坐标转换工具函数 ==============

/**
 * CDS 数据片段（用于表示单个 CDS 区域）
 */
interface ICDSSegment {
  genomicStart: number // 基因组坐标起始
  genomicEnd: number // 基因组坐标终止
  cdsStart: number // CDS 坐标起始（拼接后的位置）
  cdsEnd: number // CDS 坐标终止（拼接后的位置）
  length: number // 片段长度
}

/**
 * 解析 CDS position 数组为片段数组
 */
function parseCDSSegments(cdsPositions: number[]): ICDSSegment[] {
  const segments: ICDSSegment[] = []
  let cumulativeLength = 0

  for (let i = 0; i < cdsPositions.length; i += 2) {
    const genomicStart = cdsPositions[i]
    const genomicEnd = cdsPositions[i + 1]
    const length = genomicEnd - genomicStart

    segments.push({
      genomicStart,
      genomicEnd,
      cdsStart: cumulativeLength,
      cdsEnd: cumulativeLength + length,
      length
    })

    cumulativeLength += length
  }

  return segments
}

/**
 * 计算 CDS 总长度
 */
function calculateCDSLength(cdsPositions: number[]): number {
  let totalLength = 0
  for (let i = 0; i < cdsPositions.length; i += 2) {
    totalLength += cdsPositions[i + 1] - cdsPositions[i]
  }
  return totalLength
}

/**
 * 基因组坐标转换为 CDS 坐标
 */
function genomicToCDSCoordinate(genomicPos: number, segments: ICDSSegment[]): number | null {
  for (const segment of segments) {
    if (genomicPos >= segment.genomicStart && genomicPos < segment.genomicEnd) {
      const offsetInSegment = genomicPos - segment.genomicStart
      return segment.cdsStart + offsetInSegment
    }
  }
  return null // 不在 CDS 区域
}

/**
 * 判断基因组位置是否在 CDS 区域内
 */
function isInCDSRegion(genomicPos: number, segments: ICDSSegment[]): boolean {
  return segments.some((seg) => genomicPos >= seg.genomicStart && genomicPos < seg.genomicEnd)
}

// ============== END CDS 工具函数 ==============

// 🎨 渐变色映射函数
function getGradientColor(value: number, min: number, max: number, colormapName: string): string {
  const gradient = COLORMAP_GRADIENTS[colormapName]
  if (!gradient) return '#808080' // 默认灰色

  // 将 value 映射到 [0, 1] 范围
  const range = max - min
  if (range === 0) return gradient[0]

  const normalized = (value - min) / range
  const clampedValue = Math.max(0, Math.min(1, normalized))

  // 映射到渐变色数组索引
  const index = clampedValue * (gradient.length - 1)
  const lowerIndex = Math.floor(index)
  const upperIndex = Math.ceil(index)

  // 如果正好在某个索引上，直接返回
  if (lowerIndex === upperIndex) {
    return gradient[lowerIndex]
  }

  // 线性插值
  const lowerColor = gradient[lowerIndex]
  const upperColor = gradient[upperIndex]
  const t = index - lowerIndex

  return interpolateColor(lowerColor, upperColor, t)
}

// 🎨 颜色线性插值
function interpolateColor(color1: string, color2: string, t: number): string {
  const r1 = parseInt(color1.slice(1, 3), 16)
  const g1 = parseInt(color1.slice(3, 5), 16)
  const b1 = parseInt(color1.slice(5, 7), 16)

  const r2 = parseInt(color2.slice(1, 3), 16)
  const g2 = parseInt(color2.slice(3, 5), 16)
  const b2 = parseInt(color2.slice(5, 7), 16)

  const r = Math.round(r1 + (r2 - r1) * t)
  const g = Math.round(g1 + (g2 - g1) * t)
  const b = Math.round(b1 + (b2 - b1) * t)

  return `#${r.toString(16).padStart(2, '0')}${g.toString(16).padStart(2, '0')}${b.toString(16).padStart(2, '0')}`
}

// 🎨 检查是否为渐变色名称
function isGradientColormap(color: any): color is string {
  return typeof color === 'string' && color in COLORMAP_GRADIENTS
}

// 匹配形如 "key=value;key2=value2" 的整串（允许少量空格）
const KEY_VALUE_LIST_REGEX = /^\s*[^=;]+=[^;]+(?:\s*;\s*[^=;]+=[^;]+)*\s*$/

/**
 * 检测字符串是否为 {key}={value} 并用分号分隔的形式
 * 例如: "Name=L1MB4;Class=LINE;Family=L1"
 */
export function isKeyValueList(input: string): boolean {
  return KEY_VALUE_LIST_REGEX.test(input)
}

/**
 * 内部解析函数：把字符串拆成 { key, value } 数组
 * 若格式不合法，返回 null
 */
function parseKeyValueList(input: string): { key: string; value: string }[] | null {
  if (!isKeyValueList(input)) return null

  return input
    .trim()
    .split(/\s*;\s*/) // 按分号切分，允许左右有空格
    .map((pair) => {
      const [rawKey, rawValue] = pair.split(/\s*=\s*/) // 按等号切分，允许左右有空格
      return {
        key: rawKey.trim(),
        value: rawValue.trim()
      }
    })
}

/**
 * 提取所有 key
 * 不符合模式时返回空数组
 */
export function extractKeys(input: string): string[] {
  const pairs = parseKeyValueList(input)
  if (!pairs) return []
  return pairs.map((p) => p.key)
}

/**
 * 提取所有 value
 * 不符合模式时返回空数组
 */
export function extractValues(input: string): string[] {
  const pairs = parseKeyValueList(input)
  if (!pairs) return []
  return pairs.map((p) => p.value)
}

self.onmessage = function (e: MessageEvent<IWorkerMessage>) {
  const { data, type, plot, region, regionData, annotation, renderParams, axisType, cdsData } = e.data
  let result: any

  console.log('[CDS mode] Worker 收到消息:')
  console.log('[CDS mode] - axisType:', axisType)
  console.log('[CDS mode] - cdsData:', cdsData)
  console.log('[CDS mode] - data 长度:', data?.length)

  switch (type.toLowerCase()) {
    case 'fasta':
      result = formatFasta(data, region, plot)
      break
    case 'rna':
      result = formatRNA(data, region, plot, regionData, 'full', axisType, cdsData)
      break
    case 'ccre':
      result = formatCCRE(data, region, plot)
      break
    case 'model':
      result = formatTransModel(data, region, plot, axisType, cdsData)
      break
    case 'rbp':
      result = formatRBP(data, region, plot)
      break
    case 'sqtl':
      result = formatSQTL(data, region, plot)
      break
    case 'eqtl':
      result = formatEQTL(data, region, plot)
      break
    case 'junction':
      result = formatJunction(data, region, plot, axisType, cdsData)
      break
    case 'junction_expression':
      result = formatJunctionExpression(data, region, plot, axisType, cdsData)
      break
    case 'exon_expression':
      result = formatExonExpression(data, region, plot)
      break
    case 'modification':
      result = formatModification(data, region, plot, regionData)
      break
    case 'bed':
      result = formatBed(data, region, plot, annotation, renderParams, axisType, cdsData)
      break
    case 'ism':
      result = formatISM(data, region, plot)
      break
    case 'med':
      result = formatMed(data, region, plot)
      break
    case 'vcf':
      result = formatVCF(data, region, plot)
      break
    case 'bigwig':
      result = formatBigWig(data, region, plot, renderParams, axisType, cdsData)
      break
    case 'bigbed':
      result = formatBigBed(data, region, plot, annotation, renderParams, axisType, cdsData, regionData)
      break
    case 'gff':
      result = formatGFF(data, region, plot)
      break
    default:
      result = formatConnect(data, region, plot)
  }

  self.postMessage({ success: true, data: result })
}

