const formatCCRE = (data, region, plot) => {
  const ccre = data['ccre']
  const startSeq = region['start']
  const maxEnd = region['end']
  const ccreChildren: any[] = []
  const ccreObj: any = {}
  const startArr: any[] = []
  const endArr: any[] = []
  const namesArr: any[] = []
  const colorArr: any[] = []
  const names: any[] = []
  const colorsMap = {
    CTCF: 'red',
    Enhancer: 'yellow',
    Promoter: 'green',
    OChrom: 'red'
  }

  for (const ccreName in ccre) {
    const val = ccre[ccreName]
    const positions = val['position']
    const names = val['name']
    const ids = val['id']
    const start = positions.filter((item, index) => index % 2 === 0 && item > startSeq).map((ele) => ele - startSeq)
    const end = positions.filter((item, index) => index % 2 !== 0 && item < maxEnd).map((ele) => ele - startSeq)
    startArr.push(...start)
    endArr.push(...end)
    namesArr.push(...names)

    ccreObj[ccreName] = {
      name: ccreName,
      start: start,
      end: end,
      size: startArr.length,
      plot: plot,
      props: val
    }
  }

  for (const ccreName in ccreObj) {
    const childNames: any[] = []
    ccreObj[ccreName].start.forEach((ele, index) => {
      colorArr.push(colorsMap[ccreName])
      childNames.push({ name: namesArr[index], start: ele + startSeq, end: ccreObj[ccreName].end[index] + startSeq })
    })
    ccreChildren.push({
      name: ccreName,
      size: ccreObj[ccreName].start.length,
      plot: plot,
      color: colorsMap[ccreName],
      start: ccreObj[ccreName].start,
      end: ccreObj[ccreName].end,
      names: childNames,
      props: ccreObj[ccreName].props
    })
  }

  startArr.forEach((ele, index) => {
    names.push({ name: namesArr[index], start: ele + startSeq, end: endArr[index] + startSeq })
  })

  if (startArr.length > 0) {
    return {
      sort: 4,
      name: 'CCRE',
      plot: plot,
      size: startArr.length,
      start: startArr,
      end: endArr,
      color: colorArr,
      names: names,
      children: ccreChildren
    }
  } else {
    return undefined
  }
}

function buildGenomeToCDSMap(region, data) {
  const { strand, have_offset, offset = 0, start, end } = region
  const featuresJson = data.base
  console.log('buildGenomeToCDSMap >> ', featuresJson, region)
  const cdsPositions = featuresJson['CDS']?.position || []

  const genomeToCDSMap = {}
  const viewToGenomeMap = {}
  const cdsRanges: any[] = []

  const correctedStart = have_offset ? start + offset : start
  const correctedEnd = have_offset ? end - offset : end
  const currentOffset = have_offset ? offset : 0

  // Step 1: Filter + clip CDS ranges to visible region
  for (let i = 0; i < cdsPositions.length; i += 2) {
    const rawStart = cdsPositions[i]
    const rawEnd = cdsPositions[i + 1]

    // keep only if overlaps with corrected window
    if (rawEnd >= correctedStart && rawStart <= correctedEnd) {
      const clippedStart = Math.max(rawStart, correctedStart)
      const clippedEnd = Math.min(rawEnd, correctedEnd)
      if (clippedStart <= clippedEnd) {
        cdsRanges.push([clippedStart, clippedEnd])
      }
    }
  }

  // Step 2: Build mapping
  let viewOffset = 0
  for (const [start, end] of cdsRanges) {
    for (let i = start; i <= end; i++) {
      genomeToCDSMap[i] = viewOffset + (i - start) + currentOffset
      viewToGenomeMap[viewOffset + (i - start)] = i
    }
    viewOffset += end - start + 1
  }

  return {
    genomeToCDSMap,
    viewToGenomeMap
  }
}

const formatRNA = (data, region, plot, regionData, axis = 'full', axisType?, cdsData?) => {
  console.log('[CDS mode] formatRNA 开始处理:')
  console.log('[CDS mode] - axisType:', axisType)
  console.log('[CDS mode] - cdsData:', cdsData)

  const featuresJson = data.base
  const baseJson = data.region
  if (!featuresJson || Object.keys(featuresJson).length === 0) {
    return undefined
  }

  const { start, end, offset, strand } = region
  const startSeq = start
  const baseChildren: any[] = []
  const startTotal: any[] = []
  const endTotal: any[] = []
  const colorTotal: any[] = []
  const baseNameTotal: any[] = []
  const names: any[] = []
  const keys = ['Feature', 'Start', 'End', 'Length']
  const values: any[] = []

  const colorsMap = {
    exon: 'gray',
    CDS: 'gray',
    UTR: 'ocean',
    start_codon: 'red',
    stop_codon: 'red'
  }

  console.log('formatRNA >> ', data, region)

  // 🧬 CDS 模式处理
  let cdsSegments: ICDSSegment[] | null = null
  let totalCDSLength = 0
  let genomeToCDSMap = {}

  if (axisType === 'CDS' && cdsData?.position && cdsData.position.length > 0) {
    console.log('[CDS mode] 🧬 formatRNA 进入 CDS 模式处理')
    cdsSegments = parseCDSSegments(cdsData.position)
    totalCDSLength = calculateCDSLength(cdsData.position)
    console.log('[CDS mode] formatRNA CDS 总长度:', totalCDSLength)
    console.log('[CDS mode] formatRNA CDS 片段:', cdsSegments)
  } else if (axis === 'CDS') {
    const mapping = buildGenomeToCDSMap(region, data)
    genomeToCDSMap = mapping.genomeToCDSMap
  }

  // 预计算特征数量以优化数组分配
  let totalFeatures = 0
  for (const baseName in featuresJson) {
    const positions = featuresJson[baseName]['position']
    totalFeatures += Math.floor(positions.length / 2)
  }

  // 预分配数组以提高性能
  startTotal.length = totalFeatures
  endTotal.length = totalFeatures
  colorTotal.length = totalFeatures
  baseNameTotal.length = totalFeatures
  names.length = totalFeatures

  let featureIndex = 0

  for (const baseName in featuresJson) {
    const element = featuresJson[baseName]
    const positions = element['position']

    if (!positions || positions.length === 0) continue

    console.log(`[CDS mode] 🔍 处理 feature: ${baseName}`)
    console.log(`[CDS mode] - 原始 positions 数量: ${positions.length / 2}`)
    console.log(`[CDS mode] - 前3个位置:`, positions.slice(0, 6))

    const featureCount = Math.floor(positions.length / 2)
    const start = new Array(featureCount)
    const end = new Array(featureCount)
    const colors = new Array(featureCount)
    const baseNames = new Array(featureCount)
    const childNames = new Array(featureCount)
    const childValues = new Array(featureCount)

    let validFeatures = 0

    // 一次遍历处理所有位置计算
    for (let i = 0; i < positions.length; i += 2) {
      const rawStart = positions[i]
      const rawEnd = positions[i + 1]

      // 🧬 CDS 模式处理：找出 feature 与 CDS 片段的所有交集
      if (axisType === 'CDS' && cdsSegments) {
        let foundIntersection = false
        // 遍历所有 CDS 片段，找出与当前 feature 的交集
        for (const segment of cdsSegments) {
          const { genomicStart, genomicEnd, cdsStart, cdsEnd } = segment

          // 计算交集
          const overlapStart = Math.max(rawStart, genomicStart)
          const overlapEnd = Math.min(rawEnd, genomicEnd)

          // 如果有交集
          if (overlapStart < overlapEnd) {
            foundIntersection = true
            console.log(
              `[CDS mode] ✅ 找到交集: feature [${rawStart}, ${rawEnd}] × segment [${genomicStart}, ${genomicEnd}] = [${overlapStart}, ${overlapEnd}]`
            )

            // 转换为 CDS 坐标
            const cdsOverlapStart = genomicToCDSCoordinate(overlapStart, cdsSegments)
            const cdsOverlapEnd = genomicToCDSCoordinate(overlapEnd - 1, cdsSegments)

            console.log(`[CDS mode] - CDS 坐标: start=${cdsOverlapStart}, end=${cdsOverlapEnd}`)

            if (cdsOverlapStart !== null && cdsOverlapEnd !== null) {
              const s = Math.min(cdsOverlapStart, cdsOverlapEnd)
              const e = Math.max(cdsOverlapStart, cdsOverlapEnd) + 1

              const idx = validFeatures
              start[idx] = s
              end[idx] = e
              colors[idx] = colorsMap[baseName]
              baseNames[idx] = baseName

              const featureName = baseName.replace(/( |^)[a-z]/g, (L) => L.toUpperCase())
              const featureStart = s
              const featureEnd = e
              const featureLength = featureEnd - featureStart

              childNames[idx] = {
                name: baseName,
                start: featureStart,
                end: featureEnd,
                length: featureLength
              }

              childValues[idx] = [featureName, featureStart, featureEnd, featureLength]

              // 同时填充总数组
              startTotal[featureIndex] = s
              endTotal[featureIndex] = e
              colorTotal[featureIndex] = colors[idx]
              baseNameTotal[featureIndex] = baseName
              names[featureIndex] = {
                name: baseName,
                start: featureStart,
                end: featureEnd,
                length: featureLength
              }

              values[featureIndex] = [featureName, featureStart, featureEnd, featureLength]

              validFeatures++
              featureIndex++

              console.log(`[CDS mode] - 添加片段: CDS [${s}, ${e}], 长度 ${e - s}`)
            }
          }
        }

        if (!foundIntersection) {
          console.log(`[CDS mode] ❌ 无交集: feature [${rawStart}, ${rawEnd}] 不在任何 CDS 片段内`)
        }

        continue // 跳过后面的非 CDS 处理
      } else if (axis === 'CDS') {
        const sMapped = genomeToCDSMap[rawStart]
        const eMapped = genomeToCDSMap[rawEnd]
        if (sMapped !== undefined && eMapped !== undefined) {
          const s = Math.min(sMapped, eMapped)
          const e = Math.max(sMapped, eMapped)

          const idx = validFeatures
          start[idx] = s
          end[idx] = e
          colors[idx] = colorsMap[baseName]
          baseNames[idx] = baseName

          const featureName = baseName.replace(/( |^)[a-z]/g, (L) => L.toUpperCase())
          const featureStart = s + startSeq
          const featureEnd = e + startSeq
          const featureLength = featureEnd - featureStart

          childNames[idx] = {
            name: baseName,
            start: featureStart,
            end: featureEnd,
            length: featureLength
          }

          childValues[idx] = [featureName, featureStart, featureEnd, featureLength]

          startTotal[featureIndex] = s
          endTotal[featureIndex] = e
          colorTotal[featureIndex] = colors[idx]
          baseNameTotal[featureIndex] = baseName
          names[featureIndex] = {
            name: baseName,
            start: featureStart,
            end: featureEnd,
            length: featureLength
          }

          values[featureIndex] = [featureName, featureStart, featureEnd, featureLength]

          validFeatures++
          featureIndex++
        }
      } else {
        const s = rawStart - startSeq
        const e = rawEnd - startSeq

        const idx = validFeatures
        start[idx] = s
        end[idx] = e
        colors[idx] = colorsMap[baseName]
        baseNames[idx] = baseName

        const featureName = baseName.replace(/( |^)[a-z]/g, (L) => L.toUpperCase())
        const featureStart = s + startSeq
        const featureEnd = e + startSeq
        const featureLength = featureEnd - featureStart + 1

        childNames[idx] = {
          name: baseName,
          start: featureStart,
          end: featureEnd,
          length: featureLength
        }

        childValues[idx] = [featureName, featureStart, featureEnd, featureLength]

        startTotal[featureIndex] = s
        endTotal[featureIndex] = e
        colorTotal[featureIndex] = colors[idx]
        baseNameTotal[featureIndex] = baseName
        names[featureIndex] = {
          name: baseName,
          start: featureStart,
          end: featureEnd,
          length: featureLength
        }

        values[featureIndex] = [featureName, featureStart, featureEnd, featureLength]

        validFeatures++
        featureIndex++
      }
    }

    // 调整数组大小为实际有效特征数
    if (validFeatures < featureCount) {
      start.length = validFeatures
      end.length = validFeatures
      colors.length = validFeatures
      baseNames.length = validFeatures
      childNames.length = validFeatures
      childValues.length = validFeatures
    }

    console.log(`[CDS mode] - ${baseName} 有效 features: ${validFeatures}`)

    if (validFeatures > 0) {
      const featureName = baseName.replace(/( |^)[a-z]/g, (L) => L.toUpperCase())

      console.log(`[CDS mode] - 添加到 baseChildren: ${featureName}, size=${validFeatures}`)
      console.log(`[CDS mode] - start 数组前3个:`, start.slice(0, 3))
      console.log(`[CDS mode] - end 数组前3个:`, end.slice(0, 3))

      baseChildren.push({
        name: featureName,
        color: colorsMap[baseName],
        start: start,
        end: end,
        size: validFeatures,
        plot: plot,
        names: childNames,
        keys: keys,
        values: childValues,
        props: element
      })
    }
  } // 调整总数组大小为实际特征数
  startTotal.length = featureIndex
  endTotal.length = featureIndex
  colorTotal.length = featureIndex
  baseNameTotal.length = featureIndex
  names.length = featureIndex
  values.length = featureIndex

  console.log(`[CDS mode] 📦 formatRNA 最终统计:`)
  console.log(`[CDS mode] - 总特征数: ${featureIndex}`)
  console.log(`[CDS mode] - baseChildren 数量: ${baseChildren.length}`)
  console.log(`[CDS mode] ═══════════════════════════════════════════`)
  if (featureIndex > 0) {
    console.log(`[CDS mode] - startTotal 所有值:`, startTotal)
    console.log(`[CDS mode] - endTotal 所有值:`, endTotal)
    console.log(`[CDS mode] - baseNameTotal 所有值:`, baseNameTotal)
    console.log(`[CDS mode] 📋 所有特征详情 (共 ${featureIndex} 个):`)
    names.forEach((n, i) => {
      const typeName = baseNameTotal[i] || 'unknown'
      console.log(
        `[CDS mode]   ${i}: type="${typeName}", name="${n.name}", CDS坐标 [${n.start}, ${n.end}], 长度=${n.length || n.end - n.start}`
      )
    })
  }
  console.log(`[CDS mode] ═══════════════════════════════════════════`)

  if (featureIndex > 0) {
    // 一次性计算范围，避免重复遍历
    const minStart = Math.min(...startTotal)
    const maxEnd = Math.max(...endTotal)

    console.log(`[CDS mode] - 返回数据范围: [${minStart}, ${maxEnd}]`)

    return {
      name: 'RNA',
      sort: 3,
      plot: plot,
      size: featureIndex,
      inner: [minStart, maxEnd],
      keys: keys,
      values: values,
      color: colorTotal,
      start: startTotal,
      end: endTotal,
      names: names,
      region: baseJson,
      strand: strand,
      children: baseChildren,
      genomeToCDSMap: axis === 'CDS' ? genomeToCDSMap : undefined
    }
  } else {
    return undefined
  }
}

const formatTransModel = (data, region, plot, axisType?, cdsData?) => {
  console.log('[CDS mode] formatTransModel 开始处理:')
  console.log('[CDS mode] - axisType:', axisType)
  console.log('[CDS mode] - cdsData:', cdsData)

  const featureData = data['trans_model']

  if (featureData === undefined || featureData === null) {
    return undefined
  }

  const names: any[] = []
  const { start, end } = region

  const startSeq = start < end ? start : end
  const maxEnd = start < end ? end : start
  const exonChildren: any[] = []
  let exonStartArr: any[] = []
  let exonEndArr: any[] = []

  // 🧬 CDS 模式处理
  let cdsSegments: ICDSSegment[] | null = null
  let totalCDSLength = 0

  if (axisType === 'CDS' && cdsData?.position && cdsData.position.length > 0) {
    console.log('[CDS mode] 🧬 formatTransModel 进入 CDS 模式处理')
    cdsSegments = parseCDSSegments(cdsData.position)
    totalCDSLength = calculateCDSLength(cdsData.position)
    console.log('[CDS mode] formatTransModel CDS 总长度:', totalCDSLength)
  }

  featureData.forEach((ele) => {
    const str_feature = ele['features'].replace(new RegExp("'", 'gmi'), '"')
    const exons = JSON.parse(str_feature)['exon']

    console.log(`[CDS mode] 🔍 处理 transcript: ${ele['trans_name']}`)
    console.log(`[CDS mode] - 原始 exon 数量: ${exons.length / 2}`)
    console.log(`[CDS mode] - 前3个 exon:`, exons.slice(0, 6))

    // 🧬 CDS 模式：找出 exon 与 CDS 片段的所有交集
    if (axisType === 'CDS' && cdsSegments) {
      exonStartArr = []
      exonEndArr = []

      for (let i = 0; i < exons.length; i += 2) {
        const exonStart = exons[i]
        const exonEnd = exons[i + 1]

        let foundIntersection = false

        // 遍历所有 CDS 片段，找出与当前 exon 的交集
        for (const segment of cdsSegments) {
          const { genomicStart, genomicEnd } = segment

          // 计算交集
          const overlapStart = Math.max(exonStart, genomicStart)
          const overlapEnd = Math.min(exonEnd, genomicEnd)

          console.log(`[CDS mode] 检查交集: exon [${exonStart}, ${exonEnd}] × segment [${genomicStart}, ${genomicEnd}]`)

          // 如果有交集
          if (overlapStart < overlapEnd) {
            foundIntersection = true
            console.log(`[CDS mode] ✅ 找到交集: [${overlapStart}, ${overlapEnd}]`)

            // 转换为 CDS 坐标
            const cdsStart = genomicToCDSCoordinate(overlapStart, cdsSegments)
            const cdsEnd = genomicToCDSCoordinate(overlapEnd - 1, cdsSegments)

            console.log(`[CDS mode] - CDS 坐标: start=${cdsStart}, end=${cdsEnd}`)

            if (cdsStart !== null && cdsEnd !== null) {
              const s = Math.min(cdsStart, cdsEnd)
              const e = Math.max(cdsStart, cdsEnd) + 1
              exonStartArr.push(s)
              exonEndArr.push(e)
              console.log(`[CDS mode] - 添加 exon 片段: CDS [${s}, ${e}], 长度 ${e - s}`)
            }
          }
        }

        if (!foundIntersection) {
          console.log(`[CDS mode] ❌ 无交集: exon [${exonStart}, ${exonEnd}] 不在任何 CDS 片段内`)
        }
      }

      console.log('[CDS mode] formatTransModel 处理后的 exon 数量:', exonStartArr.length)
      console.log('[CDS mode] - exonStartArr 前5个:', exonStartArr.slice(0, 5))
      console.log('[CDS mode] - exonEndArr 前5个:', exonEndArr.slice(0, 5))
    } else {
      exonStartArr = exons.filter((item, index) => index % 2 === 0).map((ele) => ele - startSeq)
      exonEndArr = exons.filter((item, index) => index % 2 !== 0).map((ele) => ele - startSeq)
    }

    const childNames: any[] = []
    exonStartArr.forEach((ele, index) => {
      if (axisType === 'CDS') {
        // CDS 模式：坐标已经是 CDS 坐标，不需要加 startSeq
        names.push({ name: 'Exon ' + (index + 1), start: ele, end: exonEndArr[index] })
      } else {
        names.push({ name: 'Exon ' + (index + 1), start: ele + startSeq, end: exonEndArr[index] + startSeq })
      }
    })

    exonChildren.push({
      name: 'Exon',
      plot: plot,
      start: exonStartArr,
      end: exonEndArr,
      names: childNames
    })
  })

  exonStartArr.forEach((ele, index) => {
    if (axisType === 'CDS') {
      // CDS 模式：坐标已经是 CDS 坐标
      names.push({ name: 'Exon ' + (index + 1), start: ele, end: exonEndArr[index] })
    } else {
      names.push({ name: 'Exon ' + (index + 1), start: ele + startSeq, end: exonEndArr[index] + startSeq })
    }
  })

  console.log(`[CDS mode] 📦 formatTransModel 最终统计:`)
  console.log(`[CDS mode] - 总 exon 数: ${exonStartArr.length}`)
  console.log(`[CDS mode] - exonChildren 数量: ${exonChildren.length}`)
  console.log(`[CDS mode] - names 数量: ${names.length}`)
  if (names.length > 0) {
    console.log(`[CDS mode] - names 前3个:`)
    names.slice(0, 3).forEach((n, i) => {
      console.log(`[CDS mode]   ${i}: name="${n.name}", start=${n.start}, end=${n.end}`)
    })
  }

  if (exonStartArr.length > 0) {
    console.log('[CDS mode] formatTransModel 返回数据, exon 数量:', exonStartArr.length)
    console.log('[CDS mode] - 返回 start:', exonStartArr.slice(0, 5))
    console.log('[CDS mode] - 返回 end:', exonEndArr.slice(0, 5))

    return {
      sort: 1,
      name: 'Splicing',
      size: exonStartArr.length,
      plot: plot,
      start: exonStartArr,
      end: exonEndArr,
      names: names,
      children: exonChildren
    }
  } else {
    console.log('[CDS mode] formatTransModel 返回 undefined (没有 exon)')
    return undefined
  }
}

const formatRBP = (data, region, plot) => {
  const rbp = data['rbp']
  const startSeq = region['start']
  const maxEnd = region['end']
  const rbpObj = {}
  const rbpChildren: any[] = []
  const startTotal: any[] = []
  const endTotal: any[] = []
  const names: any[] = []

  for (const rbpName in rbp) {
    // if (rbpName === 'UPF1') continue
    const val = rbp[rbpName]
    const positions = val['position']
    const startArr = positions.filter((item, index) => index % 2 === 0 && item > startSeq).map((ele) => ele - startSeq)
    const endArr = positions.filter((item, index) => index % 2 !== 0 && item < maxEnd).map((ele) => ele - startSeq)
    startTotal.push(...startArr)
    endTotal.push(...endArr)

    rbpObj[rbpName] = {
      start: startArr,
      end: endArr,
      props: val
    }
  }

  for (const rbpName in rbpObj) {
    const childNames: any[] = []

    rbpObj[rbpName].start.forEach((ele, index) => {
      childNames.push({ name: rbpName, start: ele + startSeq, end: rbpObj[rbpName].end[index] + startSeq })
    })

    rbpChildren.push({
      name: rbpName,
      size: rbpObj[rbpName].start.length,
      plot: plot,
      start: rbpObj[rbpName].start,
      end: rbpObj[rbpName].end,
      names: childNames,
      props: rbpObj[rbpName].props
    })
  }

  if (startTotal.length > 0) {
    return {
      name: 'RBP',
      sort: 5,
      plot: plot,
      start: startTotal,
      end: endTotal,
      names: rbp,
      children: rbpChildren
    }
  } else {
    return undefined
  }
}

const formatSQTL = (data, region, plot) => {
  const sqtls = data['sqtl']
  const { start, end } = region
  const positions: any[] = []
  const scores: any[] = []
  const tissues: any[] = []
  const tissuesObj: any = {}
  const positionObj: any = {}
  const names: any[] = []

  if (sqtls === undefined || sqtls.length === 0) {
    return undefined
  }

  sqtls.forEach((ele) => {
    if (ele.position >= start && ele.position <= end) {
      const tissueName = ele.tissue
      if (tissueName in tissuesObj) {
        tissuesObj[tissueName].positions.push(ele.position - start)
        tissuesObj[tissueName].scores.push(ele.slope)
        tissuesObj[tissueName].props.push(ele)
      } else {
        tissuesObj[tissueName] = {
          positions: [ele.position - start],
          scores: [ele.slope],
          props: [ele]
        }
      }

      const positionX = ele.position - start
      if (positionX in positionObj) {
        positionObj[positionX] += 1
      } else {
        positionObj[positionX] = 1
      }
    }
  })

  for (const tissueName in tissuesObj) {
    const childNames: any[] = []
    const starts = tissuesObj[tissueName].positions
    const scores = tissuesObj[tissueName].scores

    tissuesObj[tissueName].positions.forEach((ele, index) => {
      childNames.push({ name: tissueName, position: starts[index] + start, score: scores[index] })
    })

    tissues.push({
      name: tissueName,
      size: starts.length,
      plot: plot,
      start: starts,
      scores: scores,
      names: childNames,
      props: tissuesObj[tissueName].props
    })
  }

  for (const positionX in positionObj) {
    positions.push(parseInt(positionX))
    scores.push(positionObj[positionX])
    names.push({ position: parseInt(positionX) + start, total: positionObj[positionX] })
  }

  let maxScore = 0
  let minScore = 0
  tissues.forEach((ele) => {
    const { scores } = ele
    scores.forEach((count) => {
      if (count > maxScore) maxScore = count
      if (count < minScore) minScore = count
    })
  })

  if (positions.length > 0) {
    // 对 start 字段去重（如果启用）
    const deduplicatedPositions = DEDUPLICATE_QTL_POSITIONS
      ? Array.from(new Set(positions)).sort((a, b) => a - b)
      : positions

    console.log(
      'deduplicatedPositions:',
      deduplicatedPositions.length,
      positions.length,
      deduplicatedPositions.slice(0, 10)
    )
    return {
      name: 'sQTLs',
      sort: 8,
      size: deduplicatedPositions.length,
      plot: plot,
      start: deduplicatedPositions,
      range: [minScore, maxScore],
      scores: scores,
      names: names,
      children: tissues
    }
  } else {
    return undefined
  }
}

