const formatJunctionExpression = (data, region, plot, axisType?, cdsData?) => {
  const juncExp = data['junc_expression']
  if (!juncExp || !juncExp.data) return

  // 🧬 CDS 模式：Junction 不存在
  // CDS 模式代表拼接后的 mRNA（只有编码序列），没有 intron，因此没有 junction
  if (axisType === 'CDS') {
    console.log('[CDS mode] formatJunctionExpression: CDS 模式不显示 junction（拼接后的 mRNA 没有 junction）')
    return undefined
  }

  const juncObj = juncExp['data']
  if (!juncObj || Object.keys(juncObj).length === 0) {
    return undefined
  }

  const { start: regionStart, end: regionEnd } = region
  const regionWidth = regionEnd - regionStart

  const startArray = juncObj['start']
  const endArray = juncObj['end']
  const countArray = juncObj['count']
  const children = juncObj['children']

  if (!startArray || startArray.length === 0) {
    return undefined
  }

  const juncStarts = []
  const juncEnds = []
  const names = []
  const values = []
  const filteredCounts = []

  // DNA/RNA 模式：正常处理 junction
  for (let i = 0; i < startArray.length; i++) {
    const jStart = startArray[i] <= regionStart ? 0 : startArray[i] - regionStart
    const jEnd = endArray[i] >= regionEnd ? regionWidth : endArray[i] - regionStart

    juncStarts.push(jStart)
    juncEnds.push(jEnd)
    filteredCounts.push(countArray[i])

    const junctionName = 'Junction ' + juncStarts.length
    names.push({
      name: junctionName,
      start: jStart + regionStart,
      end: jEnd + regionStart,
      total: countArray[i]
    })
    values.push([junctionName, countArray[i]])
  }

  if (juncStarts.length === 0) {
    return undefined
  }

  let allCounts: any[] = []
  if (children && children.length > 0) {
    let totalCountsLength = 0
    for (let i = 0; i < children.length; i++) {
      if (children[i].count) {
        totalCountsLength += children[i].count.length
      }
    }
    allCounts = new Array(totalCountsLength)

    let countIndex = 0
    for (let i = 0; i < children.length; i++) {
      const child = children[i]
      const counts = child.count
      if (!counts) continue

      const childNames = new Array(counts.length)
      const childValues = new Array(counts.length)

      for (let j = 0; j < counts.length; j++) {
        allCounts[countIndex++] = counts[j]
        const junctionName = 'Junction ' + (j + 1)
        childNames[j] = {
          name: junctionName,
          start: juncStarts[j] + regionStart,
          end: juncEnds[j] + regionStart,
          total: counts[j]
        }
        childValues[j] = [junctionName, counts[j]]
      }

      child.names = childNames
      child.start = juncStarts
      child.end = juncEnds
      child.scores = counts
      child.keys = ['Junction id', 'Expression']
      child.values = childValues
    }
  }

  const minCount = allCounts.length > 0 ? Math.min(...allCounts) : 0
  const maxCount = allCounts.length > 0 ? Math.max(...allCounts) : 0

  return {
    sort: 2,
    name: 'Junction',
    plot: plot,
    keys: ['Junction id', 'Expression'],
    values: values,
    count: axisType === 'CDS' ? filteredCounts : countArray,
    size: juncStarts.length,
    start: juncStarts,
    end: juncEnds,
    names: names,
    range: [minCount, maxCount],
    children: children
  }
}

const formatExonExpression = (data, region, plot) => {
  const exonExp = data['exon_expression']
  if (!exonExp || !exonExp.data) return

  const exonObj = exonExp['data']
  if (!exonObj || Object.keys(exonObj).length === 0) {
    return undefined
  }

  const { start: regionStart, end: regionEnd } = region
  const regionWidth = regionEnd - regionStart

  const startArray = exonObj['start']
  const endArray = exonObj['end']
  const countArray = exonObj['count']
  const children = exonObj['children']

  if (!startArray || startArray.length === 0) {
    return undefined
  }

  const exonStarts = new Array(startArray.length)
  const exonEnds = new Array(endArray.length)
  const names = new Array(startArray.length)
  const values = new Array(startArray.length)

  for (let i = 0; i < startArray.length; i++) {
    exonStarts[i] = startArray[i] <= regionStart ? 0 : startArray[i] - regionStart
    exonEnds[i] = endArray[i] >= regionEnd ? regionWidth : endArray[i] - regionStart

    const exonName = 'Exon ' + (i + 1)
    names[i] = {
      name: exonName,
      start: exonStarts[i] + regionStart,
      end: exonEnds[i] + regionStart,
      total: countArray[i]
    }
    values[i] = [exonName, countArray[i]]
  }

  let allCounts: any[] = []
  if (children && children.length > 0) {
    let totalCountsLength = 0
    for (let i = 0; i < children.length; i++) {
      if (children[i].count) {
        totalCountsLength += children[i].count.length
      }
    }
    allCounts = new Array(totalCountsLength)

    let countIndex = 0
    for (let i = 0; i < children.length; i++) {
      const child = children[i]
      const counts = child.count
      if (!counts) continue

      const childNames = new Array(counts.length)
      const childValues = new Array(counts.length)

      for (let j = 0; j < counts.length; j++) {
        allCounts[countIndex++] = counts[j]
        const exonName = 'Exon ' + (j + 1)
        childNames[j] = {
          name: exonName,
          start: exonStarts[j] + regionStart,
          end: exonEnds[j] + regionStart,
          total: counts[j]
        }
        childValues[j] = [exonName, counts[j]]
      }

      child.names = childNames
      child.start = exonStarts
      child.end = exonEnds
      child.scores = counts
      child.keys = ['Exon id', 'Expression']
      child.values = childValues
    }
  }

  const minCount = allCounts.length > 0 ? Math.min(...allCounts) : 0
  const maxCount = allCounts.length > 0 ? Math.max(...allCounts) : 0

  return {
    sort: 2,
    name: 'Exon',
    plot: plot,
    keys: ['Exon id', 'Expression'],
    values: values,
    scores: countArray,
    size: startArray.length,
    start: exonStarts,
    end: exonEnds,
    names: names,
    range: [minCount, maxCount],
    children: children
  }
}

const buildGenomeToCDSMap2 = (data, region, regionInfo) => {
  const strand = regionInfo.strand
  const offset = regionInfo.offset || 0
  const haveOffset = regionInfo.have_offset
  const cdsPositions = region.base['CDS']?.position || []

  const genomeToCDSMap = {}
  const viewToGenomeMap = {}

  const correctedStart = haveOffset ? regionInfo.start + offset : regionInfo.start
  const correctedEnd = haveOffset ? regionInfo.end - offset : regionInfo.end

  const cdsRanges: any[] = []

  // Step 1: clip CDS ranges into visible window
  for (let i = 0; i < cdsPositions.length; i += 2) {
    const rawStart = cdsPositions[i]
    const rawEnd = cdsPositions[i + 1]

    if (rawEnd >= correctedStart && rawStart <= correctedEnd) {
      const clippedStart = Math.max(rawStart, correctedStart)
      const clippedEnd = Math.min(rawEnd, correctedEnd)
      if (clippedStart <= clippedEnd) {
        cdsRanges.push([clippedStart, clippedEnd])
      }
    }
  }

  // Step 2: put data.pos into a Set
  const posSet = new Set(data.map((d) => d.pos))

  // Step 3: iterate CDS region base-by-base, assign mapping only if in posSet
  let viewOffset = 0
  if (strand === '+') {
    for (const [start, end] of cdsRanges) {
      for (let i = start; i <= end; i++) {
        if (posSet.has(i)) {
          genomeToCDSMap[i] = viewOffset
          viewToGenomeMap[viewOffset] = i
        }
        viewOffset += 1
      }
    }
  } else {
    for (let i = cdsRanges.length - 1; i >= 0; i--) {
      const [start, end] = cdsRanges[i]
      for (let j = end; j >= start; j--) {
        if (posSet.has(j)) {
          genomeToCDSMap[j] = viewOffset
          viewToGenomeMap[viewOffset] = j
        }
        viewOffset += 1
      }
    }
  }

  return {
    genomeToCDSMap,
    viewToGenomeMap
  }
}

