const formatBigBed = (data, region, plot, annotation, renderParams, axisType?, cdsData?, regionData?) => {
  console.log('[CDS mode] formatBigBed 开始处理:')
  console.log('formatBigBed >> processedData', data)
  console.log('formatBigBed >> annotation.deduplicate:', annotation?.deduplicate)
  console.log('formatBigBed >> regionData:', regionData)

  // 🧬 从 regionData 提取 gene_id（用于过滤）
  const targetGeneId = regionData?.region?.[0]?.gene_id || null
  // 去除版本号进行比较 (e.g., "ENSG00000049245.10" -> "ENSG00000049245")
  const normalizeGeneId = (id: string | null | undefined): string | null => {
    if (!id) return null
    return id.split('.')[0].toUpperCase()
  }
  const normalizedTargetGeneId = normalizeGeneId(targetGeneId)
  console.log('formatBigBed >> targetGeneId:', targetGeneId, '-> normalized:', normalizedTargetGeneId)

  // 🔍 检查 annotation.keys 中是否包含 Gene ID 相关字段
  const geneIdKeyVariants = ['Gene id', 'Gene ID', 'GeneID', 'gene_id', 'geneid', 'GENE_ID']
  const annotationKeys = annotation?.keys || []
  let geneIdKeyIndex = -1
  let matchedGeneIdKey = null

  for (const variant of geneIdKeyVariants) {
    const idx = annotationKeys.findIndex((k: string) => k === variant || k.toLowerCase() === variant.toLowerCase())
    if (idx !== -1) {
      geneIdKeyIndex = idx
      matchedGeneIdKey = annotationKeys[idx]
      break
    }
  }
  console.log('formatBigBed >> geneIdKeyIndex:', geneIdKeyIndex, 'matchedKey:', matchedGeneIdKey)

  // 🧬 CDS 模式处理：过滤和转换数据
  let processedData = data

  // 🔍 Gene ID 过滤：如果找到了 Gene ID 字段且有目标 gene_id，进行过滤
  if (normalizedTargetGeneId && geneIdKeyIndex !== -1) {
    const { sep = '|' } = annotation || {}
    const beforeFilterCount = processedData.length

    // 打印第一条数据的结构用于调试
    if (processedData.length > 0) {
      const sampleEle = processedData[0]
      const sampleRest = sampleEle.rest
      const sampleMoreInfo = sampleRest?.split('\t') || []
      const sampleProps = sampleMoreInfo[0]?.split(sep || '|') || []
      console.log('formatBigBed >> Sample data structure:')
      console.log('formatBigBed >>   - rest:', sampleRest)
      console.log('formatBigBed >>   - moreInfo[0]:', sampleMoreInfo[0])
      console.log('formatBigBed >>   - props:', sampleProps)
      console.log('formatBigBed >>   - props[geneIdKeyIndex]:', sampleProps[geneIdKeyIndex])
      console.log('formatBigBed >>   - sep:', sep)
    }

    processedData = processedData.filter((ele) => {
      const rest = ele.rest
      if (!rest) return false

      const moreInfo = rest.split('\t')
      const props = moreInfo[0].split(sep || '|')
      const eleGeneId = props[geneIdKeyIndex]
      const normalizedEleGeneId = normalizeGeneId(eleGeneId)

      return normalizedEleGeneId === normalizedTargetGeneId
    })

    console.log(
      'formatBigBed >> Gene ID filter:',
      beforeFilterCount,
      '->',
      processedData.length,
      `(filtered ${beforeFilterCount - processedData.length} items not matching ${normalizedTargetGeneId})`
    )
  } else {
    console.log(
      'formatBigBed >> Gene ID filter SKIPPED:',
      'normalizedTargetGeneId:',
      normalizedTargetGeneId,
      'geneIdKeyIndex:',
      geneIdKeyIndex
    )
  }
  let cdsSegments: ICDSSegment[] | null = null
  let totalCDSLength = 0

  if (axisType === 'CDS' && cdsData?.position && cdsData.position.length > 0) {
    console.log('[CDS mode] 🧬 进入 CDS 模式数据处理')
    cdsSegments = parseCDSSegments(cdsData.position)
    totalCDSLength = calculateCDSLength(cdsData.position)

    console.log('[CDS mode] CDS 片段数量:', cdsSegments.length)
    console.log('[CDS mode] CDS 总长度:', totalCDSLength, 'bp')

    // 过滤数据：只保留在 CDS 区域内的数据（基于已过滤的 processedData，保留 Gene ID 过滤结果）
    const beforeCDSFilterCount = processedData.length
    processedData = processedData.filter((ele) => {
      const inCDS = isInCDSRegion(ele.start, cdsSegments!)
      return inCDS
    })

    console.log('[CDS mode] 过滤后数据长度:', processedData.length, '/', beforeCDSFilterCount)
    console.log(
      '[CDS mode] 过滤比例:',
      beforeCDSFilterCount > 0 ? ((processedData.length / beforeCDSFilterCount) * 100).toFixed(1) : '0',
      '%'
    )

    // 显示前3个数据点的坐标转换
    processedData.slice(0, 3).forEach((ele, i) => {
      const cdsStart = genomicToCDSCoordinate(ele.start, cdsSegments!)
      const cdsEnd = genomicToCDSCoordinate(ele.end - 1, cdsSegments!)
      console.log(`[CDS mode] 数据点 ${i}: genomic [${ele.start}, ${ele.end}] -> CDS [${cdsStart}, ${cdsEnd}]`)
    })
  }

  let max = 0
  let min = 999

  const { keys = [], order = [], expand = false, colors = [], sep = '|' } = annotation

  // 🎯 直接使用渲染参数计算最终的像素坐标
  const cellWidth = renderParams?.cellWidth || 1
  const featureLeft = renderParams?.featureLeft || 0
  const screenWidth = renderParams?.screenWidth || 0
  const minRectWidth = renderParams?.minRectWidth ?? 1 // 🔧 最小矩形宽度，默认 1px
  const color = renderParams?.color || colors // 🎨 从 renderParams 或 annotation 获取颜色配置

  // 💎 Diamond 特殊参数
  const isDiamond = plot === 'diamond'
  const isDiamondX = plot === 'diamondX'
  const pointerTop = renderParams?.pointerTop || 0 // diamond 的 Y 坐标
  const pointRadius = renderParams?.pointRadius || 6 // diamond 的半径
  const paddingTop = renderParams?.featureTop || 0 // 用于 diamondX 动态 Y 计算
  const featureHeight = renderParams?.trackHeight - renderParams?.paddingBottom || 0 // 用于 diamondX 计算

  console.log('[render bigbed] 🔧 Worker formatBigBed - renderParams:', renderParams)
  console.log('[render bigbed] 🔧 Plot type:', plot, 'isDiamond:', isDiamond, 'isDiamondX:', isDiamondX)

  // 🎨 检查是否为渐变色
  const isGradient = isGradientColormap(color)

  if (isGradient) {
    console.log(`[render bigbed] 🎨 Using gradient colormap: ${color}`)
  }

  let colors_array
  let colors_map
  let colors_single
  let expand_index
  const colorMap = {}
  let colorIndex = 0

  // 保留基因组坐标
  const genomicStarts: number[] = []
  const genomicEnds: number[] = []

  // 像素坐标和 flank 标记
  const pixelX: number[] = [] // 渲染 X 坐标
  const pixelY: number[] = [] // 渲染 Y 坐标
  const pixelWidths: number[] = [] // 渲染宽度
  const pixelHeights: number[] = [] // 渲染高度
  const pixelAlphas: number[] = [] // 💎 透明度（diamondX 使用）
  const flankFlags: number[] = [] // flank 标记

  const scores: number[] = []
  const infos: any[] = []

  // 🎨 只在非渐变色模式下处理传统颜色配置
  if (!isGradient) {
    if (colors instanceof Array) {
      colors_array = colors
    } else if (typeof colors === 'object') {
      colors_map = colors
    } else {
      colors_single = colors
    }
  }

  if (expand !== undefined) {
    expand_index = keys?.indexOf(expand)
  }

  const childrenMap = {}
  let currentRectColor = 'grey'
  const rectColors: any[] = [] // 🎨 存储每个 feature 的颜色
  // DiamondX：动态大小和透明度基于 score
  const minSize = pointRadius * 0.3
  const maxSize = pointRadius * 1
  const lengthSize = maxSize - minSize
  const minAlpha = 0.2
  const maxAlpha = 0.6
  const lengthAlpha = maxAlpha - minAlpha

  // 🔄 去重：如果启用了 deduplicate，使用 Set 记录已处理的坐标（仅用于主数据，不影响 children）
  const shouldDeduplicate = annotation?.deduplicate === true
  const processedPositions = shouldDeduplicate ? new Set<string>() : null

  processedData.forEach((ele) => {
    // 🧬 如果是 CDS 模式，转换坐标
    let displayStart = ele.start
    let displayEnd = ele.end

    if (axisType === 'CDS' && cdsSegments) {
      const cdsStart = genomicToCDSCoordinate(ele.start, cdsSegments)
      const cdsEnd = genomicToCDSCoordinate(ele.end - 1, cdsSegments) // -1 因为 end 是开区间

      if (cdsStart !== null && cdsEnd !== null) {
        displayStart = Math.min(cdsStart, cdsEnd)
        displayEnd = Math.max(cdsStart, cdsEnd) + 1 // +1 恢复开区间
      } else {
        // 如果转换失败，跳过这个数据点（理论上不应该发生，因为已经过滤过了）
        return
      }
    }

    // 🔄 去重检查：判断是否为重复位置（用于主数据去重）
    const positionKey = `${displayStart}-${displayEnd}`
    const isDuplicate = shouldDeduplicate && processedPositions && processedPositions.has(positionKey)

    if (shouldDeduplicate && processedPositions && !isDuplicate) {
      processedPositions.add(positionKey)
    }

    // 🧬 在 CDS 模式下，displayStart/End 已经是 CDS 坐标（0-based），直接使用
    // 在其他模式下，需要减去 region.start 计算相对位置
    const scale_start = axisType === 'CDS' ? displayStart : displayStart - region.start
    const scale_end = axisType === 'CDS' ? displayEnd : displayEnd - region.start
    const region_len = axisType === 'CDS' ? totalCDSLength : region.end - region.start
    const rest = ele.rest
    const moreInfo = rest.split('\t')
    const score = moreInfo.length > 1 ? parseFloat(moreInfo[1]) : 0
    const strand = moreInfo.length > 2 ? moreInfo[2] : '.'
    const props = moreInfo[0].split(sep || '|')
    const expand_name = props[expand_index]

    // 🎯 计算像素坐标
    let pixelStart, pixelEnd, rectWidth, rectHeight, rectY, rectAlpha

    if (isDiamond) {
      // 💎 Diamond 是单点数据，只需要 start 的 X 坐标
      // x = cellWidth * (start - 1) + featureLeft
      pixelStart = cellWidth * (scale_start - 1) + featureLeft
      pixelEnd = pixelStart // diamond 是单点
      rectWidth = pointRadius * 2 // diamond 宽度
      rectHeight = pointRadius * 2 // diamond 高度
      rectY = pointerTop // diamond Y 坐标
      // rectAlpha = 0.5 // 默认透明度
      rectAlpha = 1 // 默认透明度
    } else if (isDiamondX) {
      // 根据 score 的绝对值计算大小和透明度
      const normalized = Math.abs(score)
      const dynamicSize = minSize + lengthSize * normalized
      // const dynamicAlpha = minAlpha + lengthAlpha * normalized
      const dynamicAlpha = 1

      pixelStart = cellWidth * (scale_start - 1) + featureLeft
      pixelEnd = pixelStart
      rectWidth = dynamicSize * 2
      rectHeight = dynamicSize * 2
      rectY = lengthSize + featureHeight / 2 - dynamicSize
      rectAlpha = dynamicAlpha
    } else {
      // 矩形数据：使用 start 和 end
      pixelStart = cellWidth * (scale_start - 1) + featureLeft
      pixelEnd = cellWidth * (scale_end - 1) + featureLeft
      rectWidth = Math.max(pixelEnd - pixelStart, minRectWidth)
      rectHeight = 0 // 使用 featureHeight
      rectY = 0 // 默认 Y 坐标
      rectAlpha = 1.0 // 默认不透明
    } // 🏷️ 判断 flank 标记：-1(左侧屏), 0(当前屏), 1(右侧屏)
    let flankFlag = 0
    if (pixelEnd < 0) {
      flankFlag = -1 // 完全在左侧屏
    } else if (pixelStart > screenWidth) {
      flankFlag = 1 // 完全在右侧屏
    } else if (pixelStart < 0 || pixelEnd > screenWidth) {
      flankFlag = 0 // 跨越边界，算作当前屏
    }

    // 🔄 只有非重复的数据才添加到主数据数组中
    if (!isDuplicate) {
      pixelX.push(pixelStart)
      pixelY.push(rectY)
      pixelWidths.push(rectWidth)
      pixelHeights.push(rectHeight)
      pixelAlphas.push(rectAlpha) // 💎 存储透明度
      flankFlags.push(flankFlag)
      scores.push(score)

      // 保存原始基因组坐标（主数据）
      genomicStarts.push(ele.start)
      genomicEnds.push(ele.end)

      infos.push(props)
    }

    min = score < min ? score : min
    max = score > max ? score : max

    // 🎨 计算当前 feature 的颜色（稍后处理渐变色）
    if (!isGradient) {
      if (colors_map && expand_index !== undefined) {
        currentRectColor = colors_map[expand_name]
      } else if (colors_array) {
        if (!(expand_name in colorMap)) {
          colorMap[expand_name] = colors_array[colorIndex % colors_array.length]
          colorIndex++
        }
        currentRectColor = colorMap[expand_name]
      } else if (colors_single) {
        currentRectColor = colors_single
      }
    }

    // 🎨 保存颜色到数组（渐变色稍后填充）- 只有非重复数据才添加
    if (!isDuplicate) {
      rectColors.push(currentRectColor)
    }

    // 按类型收集（children 始终包含所有数据，不受去重影响）
    if (!childrenMap[expand_name]) {
      childrenMap[expand_name] = {
        name: expand_name,
        start: [], // 基因组坐标
        end: [], // 基因组坐标
        score: [],
        color: currentRectColor,
        strand: [],
        props: [],
        keys: keys,
        order: order,
        pixelCoords: {
          // 统一的像素坐标结构
          x: [],
          y: [],
          width: [],
          height: [],
          colors: [], // 🎨 每个元素的颜色
          alpha: [], // 💎 每个元素的透明度
          flank: []
        }
      }
    }
    // 存储基因组坐标和像素坐标（children 不受去重影响，保留所有数据）
    childrenMap[expand_name].start.push(ele.start)
    childrenMap[expand_name].end.push(ele.end)
    childrenMap[expand_name].pixelCoords.x.push(pixelStart)
    childrenMap[expand_name].pixelCoords.y.push(rectY)
    childrenMap[expand_name].pixelCoords.width.push(rectWidth)
    childrenMap[expand_name].pixelCoords.height.push(rectHeight)
    childrenMap[expand_name].pixelCoords.colors.push(currentRectColor) // 🎨 存储颜色
    childrenMap[expand_name].pixelCoords.alpha.push(rectAlpha) // 💎 存储透明度
    childrenMap[expand_name].pixelCoords.flank.push(flankFlag)
    childrenMap[expand_name].score.push(score)
    childrenMap[expand_name].strand.push(strand)
    childrenMap[expand_name].props.push(props)
    // }
  })

  console.log(
    'formatBigBed >> deduplication',
    annotation,
    annotation?.deduplicate,
    processedData.length,
    processedPositions ? processedPositions.size : 0
  )

  // 🎨 为每个数据点计算渐变色（如果是渐变色模式）
  if (isGradient) {
    // 💎 DiamondX 使用固定的 -1 到 1 范围
    const colorMin = isDiamondX ? -1 : min
    const colorMax = isDiamondX ? 1 : max

    scores.forEach((s, i) => {
      const gradientColor = getGradientColor(s, colorMin, colorMax, color as string)
      rectColors[i] = gradientColor

      if (i < 3) {
        console.log(
          `[render bigbed] 🎨 Worker color ${i}: score=${s}, range=[${colorMin}, ${colorMax}], color=${gradientColor}`
        )
      }
    })

    // 🎨 更新 children 中的颜色
    for (const child of Object.values(childrenMap) as any[]) {
      child.score.forEach((s, i) => {
        const gradientColor = getGradientColor(s, colorMin, colorMax, color as string)
        child.pixelCoords.colors[i] = gradientColor
      })
    }
  } else if (isDiamondX) {
    // 💎 DiamondX 非渐变模式：使用 segmentColorMap（-1 到 1）
    scores.forEach((s, i) => {
      // 这里需要在主线程处理，因为 segmentColorMap 可能不在 Worker 中
      // 暂时保留原色，主线程会处理
    })
  }

  const children = Object.values(childrenMap)

  // � Diamond 调试日志
  if (isDiamond && pixelX.length > 0) {
    console.log('[render bigbed diamond] 🔧 Worker calculated coords:', {
      count: pixelX.length,
      sampleX: pixelX.slice(0, 3),
      sampleY: pixelY.slice(0, 3),
      sampleWidth: pixelWidths.slice(0, 3),
      sampleHeight: pixelHeights.slice(0, 3),
      pointerTop,
      pointRadius
    })
  }

  // 💎 DiamondX 调试日志
  if (isDiamondX && pixelX.length > 0) {
    console.log('[render bigbed diamondX] 🔧 Worker calculated coords:', {
      count: pixelX.length,
      sampleX: pixelX.slice(0, 3),
      sampleY: pixelY.slice(0, 3),
      sampleWidth: pixelWidths.slice(0, 3),
      sampleHeight: pixelHeights.slice(0, 3),
      sampleAlpha: pixelAlphas.slice(0, 3),
      sampleScores: scores.slice(0, 3)
    })
  }

  return {
    name: 'bigbed',
    size: processedData.length,
    plot: plot,
    start: genomicStarts, // 基因组坐标
    end: genomicEnds, // 基因组坐标
    score: scores,
    range: [min, max],
    props: processedData,
    info: infos,
    children: children,
    pixelCoords: {
      // 统一的像素坐标结构
      x: pixelX,
      y: pixelY,
      width: pixelWidths,
      height: pixelHeights,
      colors: rectColors, // 🎨 Worker 计算好的颜色数组
      alpha: pixelAlphas, // 💎 Worker 计算好的透明度数组
      flank: flankFlags
    }
  }
}

const formatVCF = (data, region, plot) => {
  console.time('formatVCF ==>')
  const starts: any[] = []
  const ends: any[] = []

  data.forEach((ele) => {
    starts.push(ele.POS - region.start + region.offset)
    ends.push(ele.POS - region.start + region.offset + 1)
  })

  console.timeEnd('formatVCF ==>')
  return {
    name: 'vcf',
    size: starts.length,
    plot: plot,
    start: starts,
    end: ends,
    range: [0, 0],
    props: data,
    children: []
  }
}

const formatBigWig = (data, region, plot, renderParams, axisType?, cdsData?) => {
  console.log('[CDS mode] formatBigWig 开始处理:')
  console.log('[CDS mode] - 原始数据长度:', data?.length)
  console.log('[CDS mode] - axisType:', axisType)
  console.log('[CDS mode] - cdsData:', cdsData)
  console.log('[CDS mode] - region:', region)

  // 🧬 CDS 模式处理：过滤和转换数据
  let processedData = data
  let cdsSegments: ICDSSegment[] | null = null
  let totalCDSLength = 0

  if (axisType === 'CDS' && cdsData?.position && cdsData.position.length > 0) {
    console.log('[CDS mode] 🧬 进入 CDS 模式数据处理')
    cdsSegments = parseCDSSegments(cdsData.position)
    totalCDSLength = calculateCDSLength(cdsData.position)

    console.log('[CDS mode] CDS 片段数量:', cdsSegments.length)
    console.log('[CDS mode] CDS 总长度:', totalCDSLength, 'bp')

    // 过滤数据：只保留在 CDS 区域内的数据
    processedData = data.filter((ele) => {
      const inCDS = isInCDSRegion(ele.start, cdsSegments!)
      return inCDS
    })

    console.log('[CDS mode] 过滤后数据长度:', processedData.length, '/', data.length)
    console.log(
      '[CDS mode] 过滤比例:',
      data.length > 0 ? ((processedData.length / data.length) * 100).toFixed(1) : '0',
      '%'
    )

    // 显示前3个数据点的坐标转换
    processedData.slice(0, 3).forEach((ele, i) => {
      const cdsStart = genomicToCDSCoordinate(ele.start, cdsSegments!)
      const cdsEnd = genomicToCDSCoordinate(ele.end - 1, cdsSegments!)
      console.log(`[CDS mode] 数据点 ${i}: genomic [${ele.start}, ${ele.end}] -> CDS [${cdsStart}, ${cdsEnd}]`)
    })
  }

  const startTotal: any[] = []
  const endTotal: any[] = []
  const score: any[] = []

  // 像素坐标
  const pixelX: number[] = [] // 渲染 X 坐标
  const pixelY: number[] = [] // 渲染 Y 坐标（bar 底部，通常是 0）
  const pixelWidths: number[] = [] // 渲染宽度
  const pixelHeights: number[] = [] // 渲染高度（bar 的高度）
  const pixelColors: string[] = [] // 渲染颜色
  const flankFlags: number[] = [] // flank 标记

  let max = 0
  let min = 999

  console.log(
    `[render bar] -region 🔧 Worker formatBigWig - region: [${region.start}, ${region.end}], dataLength: ${processedData.length}`
  )

  // 🔍 分析第一个和最后一个数据点，判断是否正确传递了 flank 区域
  if (data.length > 0) {
    const firstPoint = data[0]
    const lastPoint = data[data.length - 1]
    console.log(
      `[render bar] -region 第一个数据点: [${firstPoint.start}, ${firstPoint.end}], 相对坐标应为: ${firstPoint.start - region.start}`
    )
    console.log(
      `[render bar] -region 最后数据点: [${lastPoint.start}, ${lastPoint.end}], 相对坐标应为: ${lastPoint.end - region.start}`
    )
  }

  // 🎯 从 renderParams 提取渲染参数
  const cellWidth = renderParams?.cellWidth || 1
  const featureLeft = renderParams?.featureLeft || 0
  const featureTop = renderParams?.featureTop || 0
  const screenWidth = renderParams?.screenWidth || 0
  const trackHeight = renderParams?.trackHeight || 0
  const color = renderParams?.color
  const isBarPlot = plot === 'bar' // 判断是否为 bar 类型

  // 🎨 检查是否为渐变色
  const isGradient = isGradientColormap(color)

  if (isGradient) {
    console.log(`[render bar] 🎨 Using gradient colormap: ${color}`)
  }

  processedData.forEach((ele, i) => {
    // 🧬 如果是 CDS 模式，转换坐标
    let displayStart = ele.start
    let displayEnd = ele.end

    if (axisType === 'CDS' && cdsSegments) {
      const cdsStart = genomicToCDSCoordinate(ele.start, cdsSegments)
      const cdsEnd = genomicToCDSCoordinate(ele.end - 1, cdsSegments) // -1 因为 end 是开区间

      if (cdsStart !== null && cdsEnd !== null) {
        displayStart = Math.min(cdsStart, cdsEnd)
        displayEnd = Math.max(cdsStart, cdsEnd) + 1 // +1 恢复开区间
      } else {
        // 如果转换失败，跳过这个数据点
        return
      }
    }

    // 🧬 在 CDS 模式下，displayStart/End 已经是 CDS 坐标（0-based），直接使用
    // 在其他模式下，需要减去 region.start 计算相对位置
    const scale_start = axisType === 'CDS' ? displayStart : displayStart - region.start
    const scale_end = axisType === 'CDS' ? displayEnd : displayEnd - region.start

    // 保存基因组坐标
    startTotal.push(scale_start)
    endTotal.push(scale_end)
    score.push(ele.score)

    // 🎯 计算像素坐标
    const barX = cellWidth * scale_start + featureLeft
    const barWidth = cellWidth * (scale_end - scale_start)

    // 🏷️ 判断 flank 标记
    let flankFlag = 0
    if (barX + barWidth < 0) {
      flankFlag = -1 // 完全在左侧屏
    } else if (barX > screenWidth) {
      flankFlag = 1 // 完全在右侧屏
    }

    pixelX.push(barX)
    pixelY.push(0) // bar 底部位置，通常是 0
    pixelWidths.push(barWidth)
    pixelColors.push('') // 颜色稍后填充，在计算完 min/max 后填充
    flankFlags.push(flankFlag)

    if (i < 3) {
      console.log(
        `[render bar] 🔧 Worker point ${i}: original [${ele.start}, ${ele.end}], scaled [${scale_start}, ${scale_end}], barX=${barX.toFixed(2)}, barWidth=${barWidth.toFixed(2)}`
      )
    }

    if (ele.score > max) max = ele.score
    if (ele.score < min) min = ele.score
  })

  // 🎨 为每个数据点计算颜色（如果是渐变色）
  if (isGradient) {
    score.forEach((s, i) => {
      const gradientColor = getGradientColor(s, min, max, color as string)
      pixelColors[i] = gradientColor

      if (i < 3) {
        console.log(`[render bar] 🎨 Worker color ${i}: score=${s}, min=${min}, max=${max}, color=${gradientColor}`)
      }
    })
  } else if (typeof color === 'string') {
    // 🎨 单色填充
    score.forEach((_, i) => {
      pixelColors[i] = color
    })
  }

  // 📊 计算每个数据点的高度和 Y 坐标
  const isLinePlot = plot === 'line'
  const isPointPlot = plot === 'point'

  if ((isBarPlot || isLinePlot || isPointPlot) && trackHeight > featureTop) {
    const featureHeight = trackHeight - featureTop // 可用绘制高度
    const ruler = max - 0

    score.forEach((s, i) => {
      const barHeight = ruler === 0 ? featureHeight : (s * featureHeight) / ruler
      pixelHeights[i] = barHeight

      // 🎯 计算 Y 坐标
      if (isBarPlot) {
        // bar 类型：从底部向上绘制
        const barY = featureHeight - barHeight + featureTop
        pixelY[i] = barY
      } else if (isLinePlot || isPointPlot) {
        // line/point 类型：Y 坐标就是数据点的位置
        const dataY = featureHeight - barHeight + featureTop
        pixelY[i] = dataY
      }

      if (i < 3) {
        console.log(
          `[render ${plot}] 📊 Worker point ${i}: score=${s}, ruler=${ruler}, height=${barHeight.toFixed(2)}, y=${pixelY[i].toFixed(2)}`
        )
      }
    })
  } else {
    // TODO: 其他 plot 类型的处理
    console.log(`[render ${plot}] ⚠️ Non-bar/line/point plot type: ${plot}, skipping Y coordinate calculation`)
  }

  return {
    name: 'bigwig',
    size: startTotal.length,
    plot: plot,
    start: startTotal,
    end: endTotal,
    score: score,
    range: [min, max],
    props: data,
    children: [],
    pixelCoords: {
      x: pixelX,
      y: pixelY,
      width: pixelWidths,
      height: pixelHeights,
      colors: pixelColors,
      flank: flankFlags
    }
  }
}

const formatGFF = (data, region, plot) => {
  const startTotal: any[] = []
  const endTotal: any[] = []
  const childArr: any[] = []

  data.forEach((element) => {
    const {
      attributes: { ID, gene_id, gene_name, gene_type, havana_gene, hgnc_id, level, tag },
      child_features,
      start,
      end,
      strand
    } = element[0]
    startTotal.push(start - region.start + region.offset)
    endTotal.push(end - region.start + region.offset)

    child_features.forEach((child) => {
      const {
        attributes: { transcript_id, transcript_name, transcript_type, strand },
        child_features: rna_features,
        start,
        end
      } = child[0]

      rna_features.forEach((features) => {
        const featureStart: any[] = []
        const featureEnd: any[] = []
        const plots: any[] = []

        features.forEach((feature) => {
          const { start, end, type } = feature
          featureStart.push(start - region.start + region.offset)
          featureEnd.push(end - region.start + region.offset)
          plots.push(plot)
        })

        childArr.push({
          name: 'RNA',
          plot: plots,
          size: features.length,
          start: featureStart,
          end: featureEnd
        })
      })
    })
  })

  return {
    name: 'gff',
    size: 0,
    plot: plot,
    props: data,
    children: []
  }
}

const formatConnect = (data, region, plot) => {
  const { start, end } = region

  const props = [
    {
      start: start,
      end: end
    }
  ]

  return {
    name: 'connect',
    size: 0,
    start: [start],
    end: [end],
    plot: 'connect',
    props: props,
    children: []
  }
}
